import tiktoken

enc = tiktoken.encoding_for_model('gpt-4o-mini')

class Conversation:
    def __init__(self, system: str, max_tokens: int = 50_000):
        self.max_tokens = max_tokens
        self.history = [{'role':'system','content':system}]

    def add(self, role: str, content: str):
        self.history.append({'role':role,'content':content})
        self._trim()

    def _count(self) -> int:
        return sum(len(enc.encode(m['content']))+4 for m in self.history)

    def _trim(self):
        while self._count() > self.max_tokens and len(self.history) > 2:
            self.history = [self.history[0]] + self.history[3:]  # keep system, drop oldest turn

    def messages(self) -> list:
        return self.history

