from typing import Generator

def extract_pdf(path: str) -> str:
    reader = pypdf.PdfReader(path)
    return '\n\n'.join(
        page.extract_text() or '' for page in reader.pages
    )

def chunk(text: str, size: int=800, overlap: int=100) -> Generator[str,None,None]:
    words = text.split()
    step  = size - overlap
    for i in range(0, len(words), step):
        chunk_text = ' '.join(words[i:i+size])
        if chunk_text.strip():
            yield chunk_text

import numpy as np
from openai import OpenAI
client = OpenAI()

def embed(texts: list[str]) -> np.ndarray:
    resp = client.embeddings.create(
        model='text-embedding-3-small', input=texts
    )
    return np.array([e.embedding for e in resp.data])

def top_k(query: str, chunks: list, embeddings: np.ndarray, k=3) -> list:
    q_emb = embed([query])[0]
    scores = embeddings @ q_emb / (
        np.linalg.norm(embeddings, axis=1) * np.linalg.norm(q_emb) + 1e-9
    )
    idx = scores.argsort()[::-1][:k]
    return [chunks[i] for i in idx]

def answer(query: str, chunks: list, embeddings: np.ndarray) -> str:
    docs = top_k(query, chunks, embeddings)
    ctx  = '\n\n'.join(docs)
    resp = client.chat.completions.create(
        model='gpt-4o',
        messages=[
            {'role':'system','content':'Answer based only on the context provided.'},
            {'role':'user','content':f'Context:\n{ctx}\n\nQuestion: {query}'}
        ]
    )
    return resp.choices[0].message.content

