import redis, hashlib, json

app    = FastAPI()
client = OpenAI()
cache  = redis.Redis(host='localhost', decode_responses=True)

def classify(text: str) -> dict:
    key = 'sent:' + hashlib.sha256(text.encode()).hexdigest()[:16]
    cached = cache.get(key)
    if cached:
        return json.loads(cached)

    resp = client.chat.completions.create(
        model='gpt-4o-mini',
        messages=[{
            'role':'system',
            'content':'Reply ONLY with JSON: {"label":"positive|negative|neutral","score":0.0-1.0,"reason":"..."}'
        },{'role':'user','content':text}],
        response_format={'type':'json_object'}
    )
    result = json.loads(resp.choices[0].message.content)
    cache.setex(key, 3600, json.dumps(result))  # cache 1hr
    return result

@app.post('/sentiment')
def sentiment(text: str) -> dict:
    return classify(text)

