def translate_doc(paragraphs: list[str], target_lang: str) -> list[str]:
    # Batch into chunks of 3000 chars
    BATCH = 3000
    batch, results = '', []
    for p in paragraphs:
        if len(batch) + len(p) > BATCH and batch:
            results.extend(translate_chunk(batch, target_lang).split('\n\n'))
            batch = p
        else:
            batch += '\n\n' + p
    if batch:
        results.extend(translate_chunk(batch, target_lang).split('\n\n'))
    return results

