def get_commits(repo_path: str, since_tag: str = None) -> list[str]:
    repo = git.Repo(repo_path)
    if since_tag:
        commits = list(repo.iter_commits(f'{since_tag}..HEAD'))
    else:
        commits = list(repo.iter_commits('HEAD', max_count=50))
