from openai import OpenAI
from typing import NamedTuple
import json, networkx as nx

client = OpenAI()

class Relation(NamedTuple):
    subject: str
    predicate: str
    obj: str

def extract_triplets(text: str) -> list[Relation]:
    resp = client.chat.completions.create(
        model='gpt-4o',
        response_format={'type':'json_object'},
        messages=[{
            'role':'system',
            'content':'Extract subject-predicate-object triplets. JSON: {triplets: [{subject,predicate,object}]}'
        },{'role':'user','content':text}]
    )
    data = json.loads(resp.choices[0].message.content)
    return [Relation(**t) for t in data.get('triplets',[])]

def build_graph(docs: list[str]) -> nx.DiGraph:
    G = nx.DiGraph()
    for doc in docs:
        for r in extract_triplets(doc):
            G.add_edge(r.subject, r.obj, label=r.predicate)
    return G

