from openai import OpenAI
from langchain_community.vectorstores import FAISS
from langchain_openai import OpenAIEmbeddings
from langchain_core.documents import Document
import sqlite3, json

client = OpenAI()

class TriTierMemory:
    def __init__(self, db_path='./memory.db'):
        self.embeds = OpenAIEmbeddings()
        self.episodic = FAISS.from_documents(
            [Document(page_content='init')], self.embeds
        )
        self.conn = sqlite3.connect(db_path)
        self.conn.execute(
            'CREATE TABLE IF NOT EXISTS facts (key TEXT PRIMARY KEY, value TEXT)'
        )

    def remember_episode(self, text: str):
        self.episodic.add_documents([Document(page_content=text)])

    def recall_similar(self, query: str, k=5) -> list[str]:
        return [d.page_content for d in self.episodic.similarity_search(query, k=k)]

    def store_fact(self, key: str, value: str):
        self.conn.execute(
            'INSERT OR REPLACE INTO facts VALUES (?,?)', (key, json.dumps(value))
        )
        self.conn.commit()

    def get_fact(self, key: str):
        row = self.conn.execute('SELECT value FROM facts WHERE key=?',(key,)).fetchone()
        return json.loads(row[0]) if row else None

from openai import OpenAI
from presidio_analyzer import AnalyzerEngine
from presidio_anonymizer import AnonymizerEngine
import re

client  = OpenAI()
analyze = AnalyzerEngine()
anon    = AnonymizerEngine()

INJECTION_PATTERNS = [
    r'ignore (previous|all) instructions',
    r'you are now',
    r'DAN mode',
    r'act as if',
    r'disregard (your|all)',
]

def is_injection(text: str) -> bool:
    t = text.lower()
    return any(re.search(p, t) for p in INJECTION_PATTERNS)

def remove_pii(text: str) -> str:
    results = analyze.analyze(text=text, language='en')
    return anon.anonymize(text=text, analyzer_results=results).text

def safe_call(user_input: str, system: str) -> dict:
    if is_injection(user_input):
        return {'blocked': True, 'reason': 'Prompt injection detected'}
    clean = remove_pii(user_input)
    resp  = client.chat.completions.create(
        model='gpt-4o-mini',
        messages=[{'role':'system','content':system},{'role':'user','content':clean}]
    )
    return {'blocked': False, 'response': resp.choices[0].message.content}

