def detect_anomalies(df: pd.DataFrame, col: str) -> pd.DataFrame:
    Q1, Q3 = df[col].quantile(0.25), df[col].quantile(0.75)
    IQR = Q3 - Q1
    mask = (df[col] < Q1 - 1.5*IQR) | (df[col] > Q3 + 1.5*IQR)
    return df[mask].copy()

def explain_anomaly(row: dict, col: str, stats: dict) -> str:
    return client.chat.completions.create(
        model='gpt-4o-mini',
        messages=[{
            'role':'user',
