from transformers import AutoTokenizer

tokenizer = AutoTokenizer.from_pretrained('bert-base-cased')
label2id = {'O':0,'B-PER':1,'I-PER':2,'B-ORG':3,'I-ORG':4,'B-LOC':5,'I-LOC':6}
id2label  = {v:k for k,v in label2id.items()}

def tokenize_and_align(examples):
    enc = tokenizer(examples['tokens'], truncation=True,
                    is_split_into_words=True, padding='max_length', max_length=128)
    all_labels = []
    for i, labels in enumerate(examples['ner_tags']):
        word_ids, aligned, prev = enc.word_ids(batch_index=i), [], None
        for wid in word_ids:
            if wid is None:              aligned.append(-100)
            elif wid != prev:            aligned.append(labels[wid])
            else:
                orig = id2label[labels[wid]]
                aligned.append(label2id['I-'+orig[2:]] if orig.startswith('B-') else -100)
            prev = wid
        all_labels.append(aligned)
    enc['labels'] = all_labels
    return enc
